// ============================================
// CONSTRUCTION DE L'ARBORESCENCE GOOGLE DRIVE
// Version sans le champ parents (utilise structure plate)
// ============================================

const items = $input.all();

// Séparer dossiers et fichiers
const dossiers = [];
const fichiers = [];

for (const item of items) {
  const data = item.json;

  if (data.mimeType === 'application/vnd.google-apps.folder') {
    dossiers.push({
      id: data.id,
      nom: data.name,
      type: 'dossier',
      mimeType: data.mimeType
    });
  } else {
    fichiers.push({
      id: data.id,
      nom: data.name,
      type: 'fichier',
      mimeType: data.mimeType
    });
  }
}

// Construire la réponse
const response = {
  success: true,
  timestamp: new Date().toISOString(),
  statistiques: {
    totalDossiers: dossiers.length,
    totalFichiers: fichiers.length,
    totalElements: items.length
  },
  elements: {
    dossiers: dossiers,
    fichiers: fichiers
  }
};

return [{ json: response }];
